 case EVP_CTRL_AEAD_SET_IVLEN : if ( arg <= 0 || arg > CHACHA_CTR_SIZE ) return 0 ;
 actx -> nonce_len = arg ;
 return 1 ;
 case EVP_CTRL_AEAD_SET_IV_FIXED : if ( arg != 12 ) return 0 ;
