 struct peer * p ;
 const char * name ;
 int rc ;
 curr_unpeer = HEAD_PFIFO ( ptree -> unpeers ) ;
 for ( ;
 curr_unpeer != NULL ;
 curr_unpeer = curr_unpeer -> link ) {
