 }
 if ( cpi -> refresh_golden_frame == 1 ) cpi -> frame_flags |= FRAMEFLAGS_GOLDEN ;
 else cpi -> frame_flags &= ~ FRAMEFLAGS_GOLDEN ;
 if ( cpi -> refresh_alt_ref_frame == 1 ) cpi -> frame_flags |= FRAMEFLAGS_ALTREF ;
