 if ( strcasecmp ( p1 , "on" ) == 0 ) dcfg -> cache_trans = MODSEC_CACHE_ENABLED ;
 else if ( strcasecmp ( p1 , "off" ) == 0 ) dcfg -> cache_trans = MODSEC_CACHE_DISABLED ;
