 }
 rc = msre_parse_generic ( cmd -> pool , p2 , vartable , & error_msg ) ;
 if ( rc < 0 ) {
 return apr_psprintf ( cmd -> pool , "ModSecurity: Unable to parse options for SecCacheTransformations: %s" , error_msg ) ;
 }
 charval = apr_table_get ( vartable , "incremental" ) ;
 if ( charval != NULL ) {
