 const char * path , * error , * module , * const * wanted_modules ;
 ARRAY ( const char * ) modules ;
 bool is_master = FALSE ;
 t_array_init ( & modules , 4 ) ;
 i_zero ( & filter ) ;
 for ( ;
 * args != NULL ;
 args ++ ) {
 if ( strncmp ( * args , "service=" , 8 ) == 0 ) filter . service = * args + 8 ;
 else if ( strncmp ( * args , "module=" , 7 ) == 0 ) {
 module = * args + 7 ;
