 array_append ( & modules , & module , 1 ) ;
 }
 else if ( strncmp ( * args , "lname=" , 6 ) == 0 ) filter . local_name = * args + 6 ;
 else if ( strncmp ( * args , "lip=" , 4 ) == 0 ) {
 if ( net_addr2ip ( * args + 4 , & filter . local_net ) == 0 ) {
 filter . local_bits = IPADDR_IS_V4 ( & filter . local_net ) ? : 128 ;
 }
 }
 else if ( strncmp ( * args , "rip=" , 4 ) == 0 ) {
 if ( net_addr2ip ( * args + 4 , & filter . remote_net ) == 0 ) {
 filter . remote_bits = IPADDR_IS_V4 ( & filter . remote_net ) ? : 128 ;
 }
 }
 }
 array_append_zero ( & modules ) ;
 wanted_modules = array_count ( & modules ) == 1 ? NULL : array_idx ( & modules , 0 ) ;
 if ( is_master ) {
 path = master_service_get_config_path ( master_service ) ;
 if ( config_parse_file ( path , TRUE , NULL , & error ) <= 0 ) {
 o_stream_nsend_str ( conn -> output , t_strconcat ( "\nERROR " , error , "\n" , NULL ) ) ;
 config_connection_destroy ( conn ) ;
