 }
 }
 o_stream_cork ( conn -> output ) ;
 ctx = config_export_init ( wanted_modules , CONFIG_DUMP_SCOPE_SET , 0 , config_request_output , conn -> output ) ;
 config_export_by_filter ( ctx , & filter ) ;
 config_export_get_output ( ctx , & output ) ;
 if ( output . specific_services != NULL ) {
 const char * const * s ;
 for ( s = output . specific_services ;
 * s != NULL ;
 s ++ ) {
 o_stream_nsend_str ( conn -> output , t_strdup_printf ( "service=%s\t" , * s ) ) ;
 }
 }
