 if ( output . used_remote ) o_stream_nsend_str ( conn -> output , "used-remote\t" ) ;
 o_stream_nsend_str ( conn -> output , "\n" ) ;
 if ( config_export_finish ( & ctx ) < 0 ) {
 config_connection_destroy ( conn ) ;
