 vlc_mutex_lock ( & p_owner -> lock ) ;
 p_owner -> p_vout = p_vout ;
 DecoderUpdateFormatLocked ( p_dec ) ;
 vlc_mutex_unlock ( & p_owner -> lock ) ;
 if ( p_owner -> p_input != NULL ) input_SendEventVout ( p_owner -> p_input ) ;
 if ( p_vout == NULL ) {
