void vp9_quantize_dc ( const tran_low_t * coeff_ptr , int skip_block , const int16_t * round_ptr , const int16_t quant , tran_low_t * qcoeff_ptr , tran_low_t * dqcoeff_ptr , const int16_t dequant_ptr , uint16_t * eob_ptr ) {
 const int rc = 0 ;
