static void write_crash_report ( const char * err ) {
 char * loc = git_pathdup ( "fast_import_crash_%" PRIuMAX , ( uintmax_t ) getpid ( ) ) ;
 FILE * rpt = fopen ( loc , "w" ) ;
 struct branch * b ;
 unsigned long lu ;
 struct recent_command * rc ;
 if ( ! rpt ) {
 error ( "can't write crash report %s: %s" , loc , strerror ( errno ) ) ;
 free ( loc ) ;
 return ;
 }
 fprintf ( stderr , "fast-import: dumping crash report to %s\n" , loc ) ;
 fprintf ( rpt , "fast-import crash report:\n" ) ;
 fprintf ( rpt , " fast-import process: %" PRIuMAX "\n" , ( uintmax_t ) getpid ( ) ) ;
 fprintf ( rpt , " parent process : %" PRIuMAX "\n" , ( uintmax_t ) getppid ( ) ) ;
 fprintf ( rpt , " at %s\n" , show_date ( time ( NULL ) , 0 , DATE_MODE ( LOCAL ) ) ) ;
 fputc ( '\n' , rpt ) ;
 fputs ( "fatal: " , rpt ) ;
 fputs ( err , rpt ) ;
 fputc ( '\n' , rpt ) ;
 fputc ( '\n' , rpt ) ;
 fputs ( "Most Recent Commands Before Crash\n" , rpt ) ;
 fputs ( "---------------------------------\n" , rpt ) ;
 for ( rc = cmd_hist . next ;
 rc != & cmd_hist ;
 rc = rc -> next ) {
 if ( rc -> next == & cmd_hist ) fputs ( "* " , rpt ) ;
 else fputs ( " " , rpt ) ;
 fputs ( rc -> buf , rpt ) ;
 fputc ( '\n' , rpt ) ;
 }
 fputc ( '\n' , rpt ) ;
 fputs ( "Active Branch LRU\n" , rpt ) ;
 fputs ( "-----------------\n" , rpt ) ;
 fprintf ( rpt , " active_branches = %lu cur, %lu max\n" , cur_active_branches , max_active_branches ) ;
 fputc ( '\n' , rpt ) ;
 fputs ( " pos clock name\n" , rpt ) ;
 fputs ( " ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\n" , rpt ) ;
 for ( b = active_branches , lu = 0 ;
 b ;
 b = b -> active_next_branch ) fprintf ( rpt , " %2lu) %6" PRIuMAX " %s\n" , ++ lu , b -> last_commit , b -> name ) ;
 fputc ( '\n' , rpt ) ;
 fputs ( "Inactive Branches\n" , rpt ) ;
 fputs ( "-----------------\n" , rpt ) ;
 for ( lu = 0 ;
 lu < branch_table_sz ;
 lu ++ ) {
 for ( b = branch_table [ lu ] ;
 b ;
 b = b -> table_next_branch ) write_branch_report ( rpt , b ) ;
 }
 if ( first_tag ) {
 struct tag * tg ;
 fputc ( '\n' , rpt ) ;
 fputs ( "Annotated Tags\n" , rpt ) ;
 fputs ( "--------------\n" , rpt ) ;
 for ( tg = first_tag ;
 tg ;
 tg = tg -> next_tag ) {
 fputs ( sha1_to_hex ( tg -> sha1 ) , rpt ) ;
 fputc ( ' ' , rpt ) ;
 fputs ( tg -> name , rpt ) ;
 fputc ( '\n' , rpt ) ;
 }
 }
 fputc ( '\n' , rpt ) ;
 fputs ( "Marks\n" , rpt ) ;
 fputs ( "-----\n" , rpt ) ;
 if ( export_marks_file ) fprintf ( rpt , " exported to %s\n" , export_marks_file ) ;
 else dump_marks_helper ( rpt , 0 , marks ) ;
 fputc ( '\n' , rpt ) ;
 fputs ( "-------------------\n" , rpt ) ;
 fputs ( "END OF CRASH REPORT\n" , rpt ) ;
 fclose ( rpt ) ;
 free ( loc ) ;
 }

static int getarg ( const char * str , int code , arg_v * argp ) {
 u_long ul ;
 switch ( code & ~ OPT ) {
 case NTP_STR : argp -> string = str ;
 break ;
 case NTP_ADD : if ( ! getnetnum ( str , & argp -> netnum , NULL , 0 ) ) return 0 ;
 break ;
 case NTP_UINT : if ( '&' == str [ 0 ] ) {
 if ( ! atouint ( & str [ 1 ] , & ul ) ) {
 fprintf ( stderr , "***Association index `%s' invalid/undecodable\n" , str ) ;
 return 0 ;
 }
 if ( 0 == numassoc ) {
 dogetassoc ( stdout ) ;
 if ( 0 == numassoc ) {
 fprintf ( stderr , "***No associations found, `%s' unknown\n" , str ) ;
 return 0 ;
 }
 }
 ul = min ( ul , numassoc ) ;
 argp -> uval = assoc_cache [ ul - 1 ] . assid ;
 break ;
 }
 if ( ! atouint ( str , & argp -> uval ) ) {
 fprintf ( stderr , "***Illegal unsigned value %s\n" , str ) ;
 return 0 ;
 }
 break ;
 case NTP_INT : if ( ! atoint ( str , & argp -> ival ) ) {
 fprintf ( stderr , "***Illegal integer value %s\n" , str ) ;
 return 0 ;
 }
 break ;
 case IP_VERSION : if ( ! strcmp ( "-6" , str ) ) {
 argp -> ival = 6 ;
 }
 else if ( ! strcmp ( "-4" , str ) ) {
 argp -> ival = 4 ;
 }
 else {
 fprintf ( stderr , "***Version must be either 4 or 6\n" ) ;
 return 0 ;
 }
 break ;
 }
 return 1 ;
 }

static int do_cmd ( xd3_stream * stream , const char * buf ) {
 int ret ;
 if ( ( ret = system ( buf ) ) != 0 ) {
 if ( WIFEXITED ( ret ) ) {
 stream -> msg = "command exited non-zero" ;
 IF_DEBUG1 ( XPR ( NT "command was: %s\n" , buf ) ) ;
 }
 else {
 stream -> msg = "abnormal command termination" ;
 }
 return XD3_INTERNAL ;
 }
 return 0 ;
 }

static cmsBool WriteSegmentedCurve ( cmsIOHANDLER * io , cmsToneCurve * g ) {
 cmsUInt32Number i , j ;
 cmsCurveSegment * Segments = g -> Segments ;
 cmsUInt32Number nSegments = g -> nSegments ;
 if ( ! _cmsWriteUInt32Number ( io , cmsSigSegmentedCurve ) ) goto Error ;
 if ( ! _cmsWriteUInt32Number ( io , 0 ) ) goto Error ;
 if ( ! _cmsWriteUInt16Number ( io , ( cmsUInt16Number ) nSegments ) ) goto Error ;
 if ( ! _cmsWriteUInt16Number ( io , 0 ) ) goto Error ;
 for ( i = 0 ;
 i < nSegments - 1 ;
 i ++ ) {
 if ( ! _cmsWriteFloat32Number ( io , Segments [ i ] . x1 ) ) goto Error ;
 }
 for ( i = 0 ;
 i < g -> nSegments ;
 i ++ ) {
 cmsCurveSegment * ActualSeg = Segments + i ;
 if ( ActualSeg -> Type == 0 ) {
 if ( ! _cmsWriteUInt32Number ( io , ( cmsUInt32Number ) cmsSigSampledCurveSeg ) ) goto Error ;
 if ( ! _cmsWriteUInt32Number ( io , 0 ) ) goto Error ;
 if ( ! _cmsWriteUInt32Number ( io , ActualSeg -> nGridPoints ) ) goto Error ;
 for ( j = 0 ;
 j < g -> Segments [ i ] . nGridPoints ;
 j ++ ) {
 if ( ! _cmsWriteFloat32Number ( io , ActualSeg -> SampledPoints [ j ] ) ) goto Error ;
 }
 }
 else {
 int Type ;
 cmsUInt32Number ParamsByType [ ] = {
 4 , 5 , 5 }
 ;
 if ( ! _cmsWriteUInt32Number ( io , ( cmsUInt32Number ) cmsSigFormulaCurveSeg ) ) goto Error ;
 if ( ! _cmsWriteUInt32Number ( io , 0 ) ) goto Error ;
 Type = ActualSeg -> Type - 6 ;
 if ( Type > 2 || Type < 0 ) goto Error ;
 if ( ! _cmsWriteUInt16Number ( io , ( cmsUInt16Number ) Type ) ) goto Error ;
 if ( ! _cmsWriteUInt16Number ( io , 0 ) ) goto Error ;
 for ( j = 0 ;
 j < ParamsByType [ Type ] ;
 j ++ ) {
 if ( ! _cmsWriteFloat32Number ( io , ( cmsFloat32Number ) ActualSeg -> Params [ j ] ) ) goto Error ;
 }
 }
 }
 return TRUE ;
 Error : return FALSE ;
 }

