 if ( type == SSL3_RT_HANDSHAKE && s -> init_off != 0 ) {
 if ( frag_off > 0 ) {
 if ( s -> init_off <= DTLS1_HM_HEADER_LENGTH ) {
 return - 1 ;
 }
