 if ( ! st -> nb_index_entries ) continue ;
 for ( j = 0 ;
 j < st -> nb_index_entries ;
 j ++ ) len += st -> index_entries [ j ] . size ;
 maxpos = FFMAX ( maxpos , st -> index_entries [ j - 1 ] . pos ) ;
 lensum += len ;
 }
 if ( maxpos < avi -> io_fsize * 9 / 10 ) return 0 ;
 if ( lensum * 9 / 10 > maxpos || lensum < maxpos * 9 / 10 ) return 0 ;
 for ( i = 0 ;
 i < s -> nb_streams ;
 i ++ ) {
 int64_t len = 0 ;
 AVStream * st = s -> streams [ i ] ;
