 if ( s -> partitioned_frame ) s -> decode_mb = mpeg4_decode_partitioned_mb ;
 else s -> decode_mb = mpeg4_decode_mb ;
 time_incr = 0 ;
 while ( get_bits1 ( gb ) != 0 ) time_incr ++ ;
 check_marker ( gb , "before time_increment" ) ;
