 av_log ( s -> avctx , AV_LOG_ERROR , "hmm, seems the headers are not complete, trying to guess time_increment_bits\n" ) ;
 for ( s -> time_increment_bits = 1 ;
 s -> time_increment_bits < 16 ;
 s -> time_increment_bits ++ ) {
