 if ( s -> pp_time <= s -> pb_time || s -> pp_time <= s -> pp_time - s -> pb_time || s -> pp_time <= 0 ) {
 return FRAME_SKIPPED ;
 }
 ff_mpeg4_init_direct_mv ( s ) ;
 if ( s -> t_frame == 0 ) s -> t_frame = s -> pb_time ;
 if ( s -> t_frame == 0 ) s -> t_frame = 1 ;
