 s -> pb_field_time = ( ROUNDED_DIV ( s -> time , s -> t_frame ) - ROUNDED_DIV ( s -> last_non_b_time - s -> pp_time , s -> t_frame ) ) * 2 ;
 if ( ! s -> progressive_sequence ) {
