 if ( s -> avctx -> debug & FF_DEBUG_PTS ) av_log ( s -> avctx , AV_LOG_DEBUG , "MPEG4 PTS: %" PRId64 "\n" , s -> current_picture_ptr -> f . pts ) ;
 check_marker ( gb , "before vop_coded" ) ;
 if ( get_bits1 ( gb ) != 1 ) {
 if ( s -> avctx -> debug & FF_DEBUG_PICT_INFO ) av_log ( s -> avctx , AV_LOG_ERROR , "vop not coded\n" ) ;
 return FRAME_SKIPPED ;
 }
 if ( s -> shape != BIN_ONLY_SHAPE && ( s -> pict_type == AV_PICTURE_TYPE_P || ( s -> pict_type == AV_PICTURE_TYPE_S && s -> vol_sprite_usage == GMC_SPRITE ) ) ) {
