 char * Tok ;
 int i ;
 int64_t F = - 1 ;
 int64_t L = - 1 ;
 int Is_Suffix_byte_Range = 1 ;
 if ( * SrcRangeStr == NULL ) return - 1 ;
 Tok = StrTok ( SrcRangeStr , "," ) ;
 if ( ( Ptr = strstr ( Tok , "-" ) ) == NULL ) return - 1 ;
 * Ptr = ' ' ;
 sscanf ( Tok , "%" SCNd64 "%" SCNd64 , & F , & L ) ;
 if ( F == - 1 || L == - 1 ) {
 * Ptr = '-' ;
 for ( i = 0 ;
 i < ( int ) strlen ( Tok ) ;
 i ++ ) {
 if ( Tok [ i ] == '-' ) {
 break ;
 }
 else if ( isdigit ( Tok [ i ] ) ) {
 Is_Suffix_byte_Range = 0 ;
 break ;
 }
 }
 if ( Is_Suffix_byte_Range ) {
 * FirstByte = ( off_t ) L ;
 * LastByte = ( off_t ) F ;
 return 1 ;
 }
 }
 * FirstByte = ( off_t ) F ;
 * LastByte = ( off_t ) L ;
 return 1 ;
 }

static void ll_find_deltas ( struct object_entry * * list , unsigned list_size , int window , int depth , unsigned * processed ) {
 struct thread_params * p ;
 int i , ret , active_threads = 0 ;
 init_threaded_search ( ) ;
 if ( delta_search_threads <= 1 ) {
 find_deltas ( list , & list_size , window , depth , processed ) ;
 cleanup_threaded_search ( ) ;
 return ;
 }
 if ( progress > pack_to_stdout ) fprintf ( stderr , "Delta compression using up to %d threads.\n" , delta_search_threads ) ;
 p = xcalloc ( delta_search_threads , sizeof ( * p ) ) ;
 for ( i = 0 ;
 i < delta_search_threads ;
 i ++ ) {
 unsigned sub_size = list_size / ( delta_search_threads - i ) ;
 if ( sub_size < 2 * window && i + 1 < delta_search_threads ) sub_size = 0 ;
 p [ i ] . window = window ;
 p [ i ] . depth = depth ;
 p [ i ] . processed = processed ;
 p [ i ] . working = 1 ;
 p [ i ] . data_ready = 0 ;
 while ( sub_size && sub_size < list_size && list [ sub_size ] -> hash && list [ sub_size ] -> hash == list [ sub_size - 1 ] -> hash ) sub_size ++ ;
 p [ i ] . list = list ;
 p [ i ] . list_size = sub_size ;
 p [ i ] . remaining = sub_size ;
 list += sub_size ;
 list_size -= sub_size ;
 }
 for ( i = 0 ;
 i < delta_search_threads ;
 i ++ ) {
 if ( ! p [ i ] . list_size ) continue ;
 pthread_mutex_init ( & p [ i ] . mutex , NULL ) ;
 pthread_cond_init ( & p [ i ] . cond , NULL ) ;
 ret = pthread_create ( & p [ i ] . thread , NULL , threaded_find_deltas , & p [ i ] ) ;
 if ( ret ) die ( "unable to create thread: %s" , strerror ( ret ) ) ;
 active_threads ++ ;
 }
 while ( active_threads ) {
 struct thread_params * target = NULL ;
 struct thread_params * victim = NULL ;
 unsigned sub_size = 0 ;
 progress_lock ( ) ;
 for ( ;
 ;
 ) {
 for ( i = 0 ;
 ! target && i < delta_search_threads ;
 i ++ ) if ( ! p [ i ] . working ) target = & p [ i ] ;
 if ( target ) break ;
 pthread_cond_wait ( & progress_cond , & progress_mutex ) ;
 }
 for ( i = 0 ;
 i < delta_search_threads ;
 i ++ ) if ( p [ i ] . remaining > 2 * window && ( ! victim || victim -> remaining < p [ i ] . remaining ) ) victim = & p [ i ] ;
 if ( victim ) {
 sub_size = victim -> remaining / 2 ;
 list = victim -> list + victim -> list_size - sub_size ;
 while ( sub_size && list [ 0 ] -> hash && list [ 0 ] -> hash == list [ - 1 ] -> hash ) {
 list ++ ;
 sub_size -- ;
 }
 if ( ! sub_size ) {
 sub_size = victim -> remaining / 2 ;
 list -= sub_size ;
 }
 target -> list = list ;
 victim -> list_size -= sub_size ;
 victim -> remaining -= sub_size ;
 }
 target -> list_size = sub_size ;
 target -> remaining = sub_size ;
 target -> working = 1 ;
 progress_unlock ( ) ;
 pthread_mutex_lock ( & target -> mutex ) ;
 target -> data_ready = 1 ;
 pthread_cond_signal ( & target -> cond ) ;
 pthread_mutex_unlock ( & target -> mutex ) ;
 if ( ! sub_size ) {
 pthread_join ( target -> thread , NULL ) ;
 pthread_cond_destroy ( & target -> cond ) ;
 pthread_mutex_destroy ( & target -> mutex ) ;
 active_threads -- ;
 }
 }
 cleanup_threaded_search ( ) ;
 free ( p ) ;
 }

