 enum interesting match = revs -> diffopt . pathspec . nr == 0 ? all_entries_interesting : entry_not_interesting ;
 int baselen = base -> len ;
 if ( ! revs -> tree_objects ) return ;
 if ( ! obj ) die ( "bad tree object" ) ;
 if ( obj -> flags & ( UNINTERESTING | SEEN ) ) return ;
