 if ( val ) val = get_xbits ( & f -> gb , val ) ;
 val = val * dequant_table [ 0 ] + f -> last_dc ;
 f -> last_dc = block [ 0 ] = val ;
 i = 1 ;
 for ( ;
 ;
 ) {
 code = get_vlc2 ( & f -> pre_gb , f -> pre_vlc . table , ACDC_VLC_BITS , 3 ) ;
 if ( code == 0 ) break ;
 if ( code == 0xf0 ) {
 i += 16 ;
