 thresh_ac >>= - ( b_width_log2 ( bsize ) + b_height_log2 ( bsize ) ) ;
 thresh_dc = ( xd -> plane [ 0 ] . dequant [ 0 ] * xd -> plane [ 0 ] . dequant [ 0 ] >> 6 ) ;
 }
