static int synth_frame ( AVCodecContext * ctx , GetBitContext * gb , int frame_idx , float * samples , const double * lsps , const double * prev_lsps , float * excitation , float * synth ) {
 WMAVoiceContext * s = ctx -> priv_data ;
 int n , n_blocks_x2 , log_n_blocks_x2 , cur_pitch_val ;
 int pitch [ MAX_BLOCKS ] , last_block_pitch ;
 int bd_idx = s -> vbm_tree [ get_vlc2 ( gb , frame_type_vlc . table , 6 , 3 ) ] , block_nsamples ;
 if ( bd_idx < 0 ) {
 av_log ( ctx , AV_LOG_ERROR , "Invalid frame type VLC code, skipping\n" ) ;
 return - 1 ;
 }
 block_nsamples = MAX_FRAMESIZE / frame_descs [ bd_idx ] . n_blocks ;
 if ( frame_descs [ bd_idx ] . acb_type == ACB_TYPE_ASYMMETRIC ) {
 n_blocks_x2 = frame_descs [ bd_idx ] . n_blocks << 1 ;
 log_n_blocks_x2 = frame_descs [ bd_idx ] . log_n_blocks + 1 ;
 cur_pitch_val = s -> min_pitch_val + get_bits ( gb , s -> pitch_nbits ) ;
 cur_pitch_val = FFMIN ( cur_pitch_val , s -> max_pitch_val - 1 ) ;
 if ( s -> last_acb_type == ACB_TYPE_NONE || 20 * abs ( cur_pitch_val - s -> last_pitch_val ) > ( cur_pitch_val + s -> last_pitch_val ) ) s -> last_pitch_val = cur_pitch_val ;
 for ( n = 0 ;
 n < frame_descs [ bd_idx ] . n_blocks ;
 n ++ ) {
 int fac = n * 2 + 1 ;
 pitch [ n ] = ( MUL16 ( fac , cur_pitch_val ) + MUL16 ( ( n_blocks_x2 - fac ) , s -> last_pitch_val ) + frame_descs [ bd_idx ] . n_blocks ) >> log_n_blocks_x2 ;
 }
 s -> pitch_diff_sh16 = ( ( cur_pitch_val - s -> last_pitch_val ) << 16 ) / MAX_FRAMESIZE ;
 }
 switch ( frame_descs [ bd_idx ] . fcb_type ) {
 case FCB_TYPE_SILENCE : s -> silence_gain = wmavoice_gain_silence [ get_bits ( gb , 8 ) ] ;
 break ;
 case FCB_TYPE_AW_PULSES : aw_parse_coords ( s , gb , pitch ) ;
 break ;
 }
 for ( n = 0 ;
 n < frame_descs [ bd_idx ] . n_blocks ;
 n ++ ) {
 int bl_pitch_sh2 ;
 switch ( frame_descs [ bd_idx ] . acb_type ) {
 case ACB_TYPE_HAMMING : {
 int block_pitch , t1 = ( s -> block_conv_table [ 1 ] - s -> block_conv_table [ 0 ] ) << 2 , t2 = ( s -> block_conv_table [ 2 ] - s -> block_conv_table [ 1 ] ) << 1 , t3 = s -> block_conv_table [ 3 ] - s -> block_conv_table [ 2 ] + 1 ;
 if ( n == 0 ) {
 block_pitch = get_bits ( gb , s -> block_pitch_nbits ) ;
 }
 else block_pitch = last_block_pitch - s -> block_delta_pitch_hrange + get_bits ( gb , s -> block_delta_pitch_nbits ) ;
 last_block_pitch = av_clip ( block_pitch , s -> block_delta_pitch_hrange , s -> block_pitch_range - s -> block_delta_pitch_hrange ) ;
 if ( block_pitch < t1 ) {
 bl_pitch_sh2 = ( s -> block_conv_table [ 0 ] << 2 ) + block_pitch ;
 }
 else {
 block_pitch -= t1 ;
 if ( block_pitch < t2 ) {
 bl_pitch_sh2 = ( s -> block_conv_table [ 1 ] << 2 ) + ( block_pitch << 1 ) ;
 }
 else {
 block_pitch -= t2 ;
 if ( block_pitch < t3 ) {
 bl_pitch_sh2 = ( s -> block_conv_table [ 2 ] + block_pitch ) << 2 ;
 }
 else bl_pitch_sh2 = s -> block_conv_table [ 3 ] << 2 ;
 }
 }
 pitch [ n ] = bl_pitch_sh2 >> 2 ;
 break ;
 }
 case ACB_TYPE_ASYMMETRIC : {
 bl_pitch_sh2 = pitch [ n ] << 2 ;
 break ;
 }
 default : bl_pitch_sh2 = 0 ;
 break ;
 }
 synth_block ( s , gb , n , block_nsamples , bl_pitch_sh2 , lsps , prev_lsps , & frame_descs [ bd_idx ] , & excitation [ n * block_nsamples ] , & synth [ n * block_nsamples ] ) ;
 }
 if ( s -> do_apf ) {
 double i_lsps [ MAX_LSPS ] ;
 float lpcs [ MAX_LSPS ] ;
 for ( n = 0 ;
 n < s -> lsps ;
 n ++ ) i_lsps [ n ] = cos ( 0.5 * ( prev_lsps [ n ] + lsps [ n ] ) ) ;
 ff_acelp_lspd2lpc ( i_lsps , lpcs , s -> lsps >> 1 ) ;
 postfilter ( s , synth , samples , 80 , lpcs , & s -> zero_exc_pf [ s -> history_nsamples + MAX_FRAMESIZE * frame_idx ] , frame_descs [ bd_idx ] . fcb_type , pitch [ 0 ] ) ;
 for ( n = 0 ;
 n < s -> lsps ;
 n ++ ) i_lsps [ n ] = cos ( lsps [ n ] ) ;
 ff_acelp_lspd2lpc ( i_lsps , lpcs , s -> lsps >> 1 ) ;
 postfilter ( s , & synth [ 80 ] , & samples [ 80 ] , 80 , lpcs , & s -> zero_exc_pf [ s -> history_nsamples + MAX_FRAMESIZE * frame_idx + 80 ] , frame_descs [ bd_idx ] . fcb_type , pitch [ 0 ] ) ;
 }
 else memcpy ( samples , synth , 160 * sizeof ( synth [ 0 ] ) ) ;
 s -> frame_cntr ++ ;
 if ( s -> frame_cntr >= 0xFFFF ) s -> frame_cntr -= 0xFFFF ;
 s -> last_acb_type = frame_descs [ bd_idx ] . acb_type ;
 switch ( frame_descs [ bd_idx ] . acb_type ) {
 case ACB_TYPE_NONE : s -> last_pitch_val = 0 ;
 break ;
 case ACB_TYPE_ASYMMETRIC : s -> last_pitch_val = cur_pitch_val ;
 break ;
 case ACB_TYPE_HAMMING : s -> last_pitch_val = pitch [ frame_descs [ bd_idx ] . n_blocks - 1 ] ;
 break ;
 }
 return 0 ;
 }

static int decode_frame ( AVCodecContext * avctx , void * data , int * got_frame , AVPacket * avpkt ) {
 int h , w , ret ;
 AVFrame * pic = data ;
 const uint32_t * src = ( const uint32_t * ) avpkt -> data ;
 int aligned_width = FFALIGN ( avctx -> width , 64 ) ;
 uint8_t * dst_line ;
 if ( avpkt -> size < 4 * aligned_width * avctx -> height ) {
 av_log ( avctx , AV_LOG_ERROR , "packet too small\n" ) ;
 return AVERROR_INVALIDDATA ;
 }
 if ( ( ret = ff_get_buffer ( avctx , pic , 0 ) ) < 0 ) return ret ;
 pic -> pict_type = AV_PICTURE_TYPE_I ;
 pic -> key_frame = 1 ;
 dst_line = pic -> data [ 0 ] ;
 for ( h = 0 ;
 h < avctx -> height ;
 h ++ ) {
 uint16_t * dst = ( uint16_t * ) dst_line ;
 for ( w = 0 ;
 w < avctx -> width ;
 w ++ ) {
 uint32_t pixel = av_be2ne32 ( * src ++ ) ;
 uint16_t r , g , b ;
 if ( avctx -> codec_id == AV_CODEC_ID_R210 ) {
 b = pixel << 6 ;
 g = ( pixel >> 4 ) & 0xffc0 ;
 r = ( pixel >> 14 ) & 0xffc0 ;
 }
 else {
 b = pixel << 4 ;
 g = ( pixel >> 6 ) & 0xffc0 ;
 r = ( pixel >> 16 ) & 0xffc0 ;
 }
 * dst ++ = r | ( r >> 10 ) ;
 * dst ++ = g | ( g >> 10 ) ;
 * dst ++ = b | ( b >> 10 ) ;
 }
 src += aligned_width - avctx -> width ;
 dst_line += pic -> linesize [ 0 ] ;
 }
 * got_frame = 1 ;
 return avpkt -> size ;
 }

static gcry_err_code_t sexp_to_enc ( gcry_sexp_t sexp , gcry_mpi_t * * retarray , gcry_module_t * retalgo , int * ret_modern , int * flags , struct pk_encoding_ctx * ctx ) {
 gcry_err_code_t err = 0 ;
 gcry_sexp_t list = NULL , l2 = NULL ;
 gcry_pk_spec_t * pubkey = NULL ;
 gcry_module_t module = NULL ;
 char * name = NULL ;
 size_t n ;
 int parsed_flags = 0 ;
 const char * elems ;
 gcry_mpi_t * array = NULL ;
 * ret_modern = 0 ;
 list = gcry_sexp_find_token ( sexp , "enc-val" , 0 ) ;
 if ( ! list ) {
 err = GPG_ERR_INV_OBJ ;
 goto leave ;
 }
 l2 = gcry_sexp_nth ( list , 1 ) ;
 if ( ! l2 ) {
 err = GPG_ERR_NO_OBJ ;
 goto leave ;
 }
 name = _gcry_sexp_nth_string ( l2 , 0 ) ;
 if ( ! name ) {
 err = GPG_ERR_INV_OBJ ;
 goto leave ;
 }
 if ( ! strcmp ( name , "flags" ) ) {
 const char * s ;
 int i ;
 * ret_modern = 1 ;
 for ( i = gcry_sexp_length ( l2 ) - 1 ;
 i > 0 ;
 i -- ) {
 s = gcry_sexp_nth_data ( l2 , i , & n ) ;
 if ( ! s ) ;
 else if ( n == 3 && ! memcmp ( s , "raw" , 3 ) && ctx -> encoding == PUBKEY_ENC_UNKNOWN ) ctx -> encoding = PUBKEY_ENC_RAW ;
 else if ( n == 5 && ! memcmp ( s , "pkcs1" , 5 ) && ctx -> encoding == PUBKEY_ENC_UNKNOWN ) ctx -> encoding = PUBKEY_ENC_PKCS1 ;
 else if ( n == 4 && ! memcmp ( s , "oaep" , 4 ) && ctx -> encoding == PUBKEY_ENC_UNKNOWN ) ctx -> encoding = PUBKEY_ENC_OAEP ;
 else if ( n == 3 && ! memcmp ( s , "pss" , 3 ) && ctx -> encoding == PUBKEY_ENC_UNKNOWN ) {
 err = GPG_ERR_CONFLICT ;
 goto leave ;
 }
 else if ( n == 11 && ! memcmp ( s , "no-blinding" , 11 ) ) parsed_flags |= PUBKEY_FLAG_NO_BLINDING ;
 else {
 err = GPG_ERR_INV_FLAG ;
 goto leave ;
 }
 }
 gcry_sexp_release ( l2 ) ;
 if ( ctx -> encoding == PUBKEY_ENC_OAEP ) {
 l2 = gcry_sexp_find_token ( list , "hash-algo" , 0 ) ;
 if ( l2 ) {
 s = gcry_sexp_nth_data ( l2 , 1 , & n ) ;
 if ( ! s ) err = GPG_ERR_NO_OBJ ;
 else {
 ctx -> hash_algo = get_hash_algo ( s , n ) ;
 if ( ! ctx -> hash_algo ) err = GPG_ERR_DIGEST_ALGO ;
 }
 gcry_sexp_release ( l2 ) ;
 if ( err ) goto leave ;
 }
 l2 = gcry_sexp_find_token ( list , "label" , 0 ) ;
 if ( l2 ) {
 s = gcry_sexp_nth_data ( l2 , 1 , & n ) ;
 if ( ! s ) err = GPG_ERR_NO_OBJ ;
 else if ( n > 0 ) {
 ctx -> label = gcry_malloc ( n ) ;
 if ( ! ctx -> label ) err = gpg_err_code_from_syserror ( ) ;
 else {
 memcpy ( ctx -> label , s , n ) ;
 ctx -> labellen = n ;
 }
 }
 gcry_sexp_release ( l2 ) ;
 if ( err ) goto leave ;
 }
 }
 for ( i = 2 ;
 ( l2 = gcry_sexp_nth ( list , i ) ) != NULL ;
 i ++ ) {
 s = gcry_sexp_nth_data ( l2 , 0 , & n ) ;
 if ( ! ( n == 9 && ! memcmp ( s , "hash-algo" , 9 ) ) && ! ( n == 5 && ! memcmp ( s , "label" , 5 ) ) && ! ( n == 15 && ! memcmp ( s , "random-override" , 15 ) ) ) break ;
 gcry_sexp_release ( l2 ) ;
 }
 if ( ! l2 ) {
 err = GPG_ERR_NO_OBJ ;
 goto leave ;
 }
 gcry_free ( name ) ;
 name = _gcry_sexp_nth_string ( l2 , 0 ) ;
 if ( ! name ) {
 err = GPG_ERR_INV_OBJ ;
 goto leave ;
 }
 gcry_sexp_release ( list ) ;
 list = l2 ;
 l2 = NULL ;
 }
 ath_mutex_lock ( & pubkeys_registered_lock ) ;
 module = gcry_pk_lookup_name ( name ) ;
 ath_mutex_unlock ( & pubkeys_registered_lock ) ;
 if ( ! module ) {
 err = GPG_ERR_PUBKEY_ALGO ;
 goto leave ;
 }
 pubkey = ( gcry_pk_spec_t * ) module -> spec ;
 elems = pubkey -> elements_enc ;
 array = gcry_calloc ( strlen ( elems ) + 1 , sizeof ( * array ) ) ;
 if ( ! array ) {
 err = gpg_err_code_from_syserror ( ) ;
 goto leave ;
 }
 err = sexp_elements_extract ( list , elems , array , NULL ) ;
 leave : gcry_sexp_release ( list ) ;
 gcry_sexp_release ( l2 ) ;
 gcry_free ( name ) ;
 if ( err ) {
 ath_mutex_lock ( & pubkeys_registered_lock ) ;
 _gcry_module_release ( module ) ;
 ath_mutex_unlock ( & pubkeys_registered_lock ) ;
 gcry_free ( array ) ;
 gcry_free ( ctx -> label ) ;
 ctx -> label = NULL ;
 }
 else {
 * retarray = array ;
 * retalgo = module ;
 * flags = parsed_flags ;
 }
 return err ;
 }

