static inline void xan_wc3_output_pixel_run ( XanContext * s , const unsigned char * pixel_buffer , int x , int y , int pixel_count ) {
 int stride ;
 int line_inc ;
 int index ;
 int current_x ;
 int width = s -> avctx -> width ;
 unsigned char * palette_plane ;
 palette_plane = s -> current_frame . data [ 0 ] ;
 stride = s -> current_frame . linesize [ 0 ] ;
 line_inc = stride - width ;
 index = y * stride + x ;
 current_x = x ;
 while ( pixel_count && index < s -> frame_size ) {
 int count = FFMIN ( pixel_count , width - current_x ) ;
 memcpy ( palette_plane + index , pixel_buffer , count ) ;
 pixel_count -= count ;
 index += count ;
 pixel_buffer += count ;
 current_x += count ;
 if ( current_x >= width ) {
 index += line_inc ;
 current_x = 0 ;
 }
 }
 }

static gboolean proto_tree_traverse_pre_order ( proto_tree * tree , proto_tree_traverse_func func , gpointer data ) {
 proto_node * pnode = tree ;
 proto_node * child ;
 proto_node * current ;
 if ( func ( pnode , data ) ) return TRUE ;
 child = pnode -> first_child ;
 while ( child != NULL ) {
 current = child ;
 child = current -> next ;
 if ( proto_tree_traverse_pre_order ( ( proto_tree * ) current , func , data ) ) return TRUE ;
 }
 return FALSE ;
 }

CURLcode Curl_add_timecondition ( struct Curl_easy * data , Curl_send_buffer * req_buffer ) {
 const struct tm * tm ;
 char * buf = data -> state . buffer ;
 struct tm keeptime ;
 CURLcode result ;
 if ( data -> set . timecondition == CURL_TIMECOND_NONE ) return CURLE_OK ;
 result = Curl_gmtime ( data -> set . timevalue , & keeptime ) ;
 if ( result ) {
 failf ( data , "Invalid TIMEVALUE" ) ;
 return result ;
 }
 tm = & keeptime ;
 snprintf ( buf , BUFSIZE - 1 , "%s, %02d %s %4d %02d:%02d:%02d GMT" , Curl_wkday [ tm -> tm_wday ? tm -> tm_wday - 1 : 6 ] , tm -> tm_mday , Curl_month [ tm -> tm_mon ] , tm -> tm_year + 1900 , tm -> tm_hour , tm -> tm_min , tm -> tm_sec ) ;
 switch ( data -> set . timecondition ) {
 default : break ;
 case CURL_TIMECOND_IFMODSINCE : result = Curl_add_bufferf ( req_buffer , "If-Modified-Since: %s\r\n" , buf ) ;
 break ;
 case CURL_TIMECOND_IFUNMODSINCE : result = Curl_add_bufferf ( req_buffer , "If-Unmodified-Since: %s\r\n" , buf ) ;
 break ;
 case CURL_TIMECOND_LASTMOD : result = Curl_add_bufferf ( req_buffer , "Last-Modified: %s\r\n" , buf ) ;
 break ;
 }
 return result ;
 }

