 }
 }
 calc_segtree_probs ( no_pred_segcounts , no_pred_tree ) ;
 no_pred_cost = cost_segmap ( no_pred_segcounts , no_pred_tree ) ;
 if ( ! frame_is_intra_only ( cm ) ) {
 calc_segtree_probs ( t_unpred_seg_counts , t_pred_tree ) ;
