 pic_frame_idx = pic -> long_ref ? pic -> pic_id : pic -> frame_num ;
 render_ref = ( struct vdpau_render_state * ) pic -> f . data [ 0 ] ;
 assert ( render_ref ) ;
 rf2 = & render -> info . h264 . referenceFrames [ 0 ] ;
 while ( rf2 != rf ) {
