 pred = ff_msmpeg4_pred_dc ( s , n , & dc_val , dir_ptr ) ;
 level += pred ;
 if ( n < 4 ) {
 * dc_val = level * s -> y_dc_scale ;
 }
 else {
 * dc_val = level * s -> c_dc_scale ;
 }
 }
 return level ;
 }

