 else evhttp_request_dispatch ( evcon ) ;
 }
 else if ( ! need_close ) {
 evhttp_connection_start_detectclose ( evcon ) ;
 }
 }
 else if ( evcon -> state != EVCON_DISCONNECTED ) {
 evcon -> state = EVCON_WRITING ;
 }
 ( * req -> cb ) ( req , req -> cb_arg ) ;
 if ( con_outgoing ) {
 evhttp_request_free ( req ) ;
 }
 }

