static int read_access_unit ( AVCodecContext * avctx , void * data , int * got_frame_ptr , AVPacket * avpkt ) {
 const uint8_t * buf = avpkt -> data ;
 int buf_size = avpkt -> size ;
 MLPDecodeContext * m = avctx -> priv_data ;
 GetBitContext gb ;
 unsigned int length , substr ;
 unsigned int substream_start ;
 unsigned int header_size = 4 ;
 unsigned int substr_header_size = 0 ;
 uint8_t substream_parity_present [ MAX_SUBSTREAMS ] ;
 uint16_t substream_data_len [ MAX_SUBSTREAMS ] ;
 uint8_t parity_bits ;
 int ret ;
 if ( buf_size < 4 ) return 0 ;
 length = ( AV_RB16 ( buf ) & 0xfff ) * 2 ;
 if ( length < 4 || length > buf_size ) return AVERROR_INVALIDDATA ;
 init_get_bits ( & gb , ( buf + 4 ) , ( length - 4 ) * 8 ) ;
 m -> is_major_sync_unit = 0 ;
 if ( show_bits_long ( & gb , 31 ) == ( 0xf8726fba >> 1 ) ) {
 if ( read_major_sync ( m , & gb ) < 0 ) goto error ;
 m -> is_major_sync_unit = 1 ;
 header_size += 28 ;
 }
 if ( ! m -> params_valid ) {
 av_log ( m -> avctx , AV_LOG_WARNING , "Stream parameters not seen;
 skipping frame.\n" ) ;
 * got_frame_ptr = 0 ;
 return length ;
 }
 substream_start = 0 ;
 for ( substr = 0 ;
 substr < m -> num_substreams ;
 substr ++ ) {
 int extraword_present , checkdata_present , end , nonrestart_substr ;
 extraword_present = get_bits1 ( & gb ) ;
 nonrestart_substr = get_bits1 ( & gb ) ;
 checkdata_present = get_bits1 ( & gb ) ;
 skip_bits1 ( & gb ) ;
 end = get_bits ( & gb , 12 ) * 2 ;
 substr_header_size += 2 ;
 if ( extraword_present ) {
 if ( m -> avctx -> codec_id == AV_CODEC_ID_MLP ) {
 av_log ( m -> avctx , AV_LOG_ERROR , "There must be no extraword for MLP.\n" ) ;
 goto error ;
 }
 skip_bits ( & gb , 16 ) ;
 substr_header_size += 2 ;
 }
 if ( ! ( nonrestart_substr ^ m -> is_major_sync_unit ) ) {
 av_log ( m -> avctx , AV_LOG_ERROR , "Invalid nonrestart_substr.\n" ) ;
 goto error ;
 }
 if ( end + header_size + substr_header_size > length ) {
 av_log ( m -> avctx , AV_LOG_ERROR , "Indicated length of substream %d data goes off end of " "packet.\n" , substr ) ;
 end = length - header_size - substr_header_size ;
 }
 if ( end < substream_start ) {
 av_log ( avctx , AV_LOG_ERROR , "Indicated end offset of substream %d data " "is smaller than calculated start offset.\n" , substr ) ;
 goto error ;
 }
 if ( substr > m -> max_decoded_substream ) continue ;
 substream_parity_present [ substr ] = checkdata_present ;
 substream_data_len [ substr ] = end - substream_start ;
 substream_start = end ;
 }
 parity_bits = ff_mlp_calculate_parity ( buf , 4 ) ;
 parity_bits ^= ff_mlp_calculate_parity ( buf + header_size , substr_header_size ) ;
 if ( ( ( ( parity_bits >> 4 ) ^ parity_bits ) & 0xF ) != 0xF ) {
 av_log ( avctx , AV_LOG_ERROR , "Parity check failed.\n" ) ;
 goto error ;
 }
 buf += header_size + substr_header_size ;
 for ( substr = 0 ;
 substr <= m -> max_decoded_substream ;
 substr ++ ) {
 SubStream * s = & m -> substream [ substr ] ;
 init_get_bits ( & gb , buf , substream_data_len [ substr ] * 8 ) ;
 m -> matrix_changed = 0 ;
 memset ( m -> filter_changed , 0 , sizeof ( m -> filter_changed ) ) ;
 s -> blockpos = 0 ;
 do {
