static float eval_lpc_spectrum ( const float * lsp , float cos_val , int order ) {
 int j ;
 float p = 0.5f ;
 float q = 0.5f ;
 float two_cos_w = 2.0f * cos_val ;
 for ( j = 0 ;
 j + 1 < order ;
 j += 2 * 2 ) {
 q *= lsp [ j ] - two_cos_w ;
 p *= lsp [ j + 1 ] - two_cos_w ;
 q *= lsp [ j + 2 ] - two_cos_w ;
 p *= lsp [ j + 3 ] - two_cos_w ;
 }
 p *= p * ( 2.0f - two_cos_w ) ;
 q *= q * ( 2.0f + two_cos_w ) ;
 return 0.5 / ( p + q ) ;
 }

static uint8_t lut_interp_linear_precache_output ( uint32_t input_value , uint16_t * table , size_t length ) {
