 quant = i == 0 ? vp9_dc_quant ( q , cm -> uv_dc_delta_q ) : vp9_ac_quant ( q , cm -> uv_ac_delta_q ) ;
 invert_quant ( & quants -> uv_quant [ q ] [ i ] , & quants -> uv_quant_shift [ q ] [ i ] , quant ) ;
