 for ( i = 0 ;
 i < oxcf -> number_of_layers && i < VPX_TS_MAX_LAYERS ;
 ++ i ) {
 LAYER_CONTEXT * lc = & cpi -> layer_context [ i ] ;
 lc -> framerate = cpi -> ref_framerate / oxcf -> rate_decimator [ i ] ;
