static UBool isPNJConsonant ( UChar32 c ) {
 if ( c < 0xa00 || 0xa50 <= c ) {
 return FALSE ;
 }
 else {
 return ( UBool ) ( pnjMap [ c - 0xa00 ] & 1 ) ;
 }
 }

u_short varfmt ( const char * varname ) {
 u_int n ;
 for ( n = 0 ;
 n < COUNTOF ( cookedvars ) ;
 n ++ ) if ( ! strcmp ( varname , cookedvars [ n ] . varname ) ) return cookedvars [ n ] . fmt ;
 return PADDING ;
 }
